from pptx import Presentation; from pptx.dml.color import RGBColor; p = Presentation('/tmp/pptx-eval/microservices.pptx'); light_count = 0; dark_count = 0;
for slide in p.slides[1:]:
    bg = slide.background.fill
    try:
        bg.fore_color.rgb
        r,g,b = bg.fore_color.rgb
        if r+g+b > 500: light_count+=1
        else: dark_count+=1
    except: light_count+=1
assert light_count >= dark_count, f'Too many dark slides: {dark_count} dark vs {light_count} light'
